import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
/**
 * On a logged-out run, openStudioTo fires onLoginRequired/onAuthenticated
 * (synchronously, before it resolves) and the command emits session-ready only
 * after openStudioTo returns. So the stdout order MUST be
 * auth-required -> authenticated -> session-ready. This pins that the command
 * wires the login callbacks and doesn't reorder session-ready ahead of them.
 */
const emitted = [];
vi.mock("../output.js", () => ({
    emitJson: (obj) => {
        emitted.push(obj);
    },
    blockingNote: (until) => `BLOCKING: ${until}`,
    printBlockingNotice: () => { },
}));
vi.mock("../config.js", () => ({
    getConfig: () => ({ serviceUrl: "https://test.invalid", apiKey: null }),
    hasCredentials: () => false,
}));
const mockOpenStudioTo = vi.fn(async (_path, opts) => {
    opts.onLoginRequired?.("sess-1", "https://test.invalid/studio/sign-in");
    opts.onAuthenticated?.("sess-1");
    return {
        sessionId: "sess-1",
        serviceUrl: "https://test.invalid",
        apiKey: "key",
        opened: true,
        abort: vi.fn(),
        done: Promise.resolve(),
    };
});
vi.mock("./openStudioTo.js", () => ({
    openStudioTo: (...args) => mockOpenStudioTo(...args),
    handleStudioError: (err) => {
        throw err;
    },
    emitWindowOpened: () => { },
}));
const TEST_RUN_ID = "11111111-1111-4111-8111-111111111111";
let savedArgv;
beforeEach(() => {
    emitted.length = 0;
    savedArgv = process.argv;
    process.argv = ["node", "openExperiments.js", TEST_RUN_ID];
    vi.spyOn(process, "exit").mockImplementation((() => { }));
});
afterEach(() => {
    process.argv = savedArgv;
    vi.restoreAllMocks();
    mockOpenStudioTo.mockClear();
});
describe("runOpenExperiments auth event ordering", () => {
    it("emits auth-required then authenticated before session-ready when logged out", async () => {
        const { runOpenExperiments } = await import("./openExperiments.js");
        await runOpenExperiments({});
        const order = emitted.map((event) => event.event);
        expect(order.slice(0, 3)).toEqual([
            "auth-required",
            "authenticated",
            "session-ready",
        ]);
    });
});
